const { execSync } = require('child_process');
const data = $input.item.json;
const title = (data.query && data.query.title) ? data.query.title : data.title;
const body = (data.query && data.query.body) ? data.query.body : (data.body || '');
if (!title) { return [{ json: { stdout: '', stderr: 'No title provided.' } }]; }
try {
  // Using echo and piping to handle multiline body safely, and avoiding raw quotes in CLI arguments
  const safeTitle = title.replace(/'/g, "'\\''");
  const safeBody = body.replace(/'/g, "'\\''");
  const cmd = `echo '${safeBody}' | gh issue create --title '${safeTitle}' --body-file -`;
  const stdout = execSync(cmd, { encoding: 'utf8', timeout: 30000 });
  return [{ json: { stdout: stdout || 'Done.', stderr: '' } }];
} catch(e) {
  return [{ json: { stdout: e.stdout || '', stderr: e.stderr || e.message } }];
}
